SELECT bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs WHERE bs.upgrade = 0 AND bs.state IN ('CO', 'NM') AND (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state) IN (SELECT bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs WHERE bs.upgrade IN (1, 2) AND bs.applicability = true GROUP BY bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state HAVING count(distinct(bs.upgrade)) = 2)